     1	using InventoryFlow.Domain.Common;
     2	using InventoryFlow.Domain.Exceptions;
     3	
     4	namespace InventoryFlow.Domain.Entities;
     5	
     6	/// <summary>
     7	/// Represents a hashed refresh token issued to an authenticated user.
     8	/// </summary>
     9	public sealed class RefreshToken : Entity<Guid>
    10	{
    11	    /// <summary>
    12	    /// Initializes a new instance of the <see cref="RefreshToken"/> class.
    13	    /// </summary>
    14	    /// <param name="id">The refresh-token identifier.</param>
    15	    /// <param name="userId">The identifier of the token owner.</param>
    16	    /// <param name="tokenHash">The one-way hash of the issued refresh token.</param>
    17	    /// <param name="expiresAtUtc">The UTC instant after which the token cannot be used.</param>
    18	    /// <exception cref="DomainException">Thrown when an identifier or token hash is empty, or the expiration is not UTC.</exception>
    19	    public RefreshToken(
    20	        Guid id,
    21	        Guid userId,
    22	        Guid familyId,
    23	        string tokenHash,
    24	        DateTimeOffset expiresAtUtc)
    25	        : base(id)
    26	    {
    27	        if (id == Guid.Empty)
    28	        {
    29	            throw new DomainException("Refresh token identifier is required.");
    30	        }
    31	
    32	        if (userId == Guid.Empty)
    33	        {
    34	            throw new DomainException("Refresh token user identifier is required.");
    35	        }
    36	
    37	        if (familyId == Guid.Empty)
    38	        {
    39	            throw new DomainException("Refresh token family identifier is required.");
    40	        }
    41	
    42	        if (string.IsNullOrWhiteSpace(tokenHash))
    43	        {
    44	            throw new DomainException("Refresh token hash is required.");
    45	        }
    46	
    47	        if (expiresAtUtc.Offset != TimeSpan.Zero)
    48	        {
    49	            throw new DomainException("Refresh token expiration must be in UTC.");
    50	        }
    51	
    52	        UserId = userId;
    53	        FamilyId = familyId;
    54	        TokenHash = tokenHash;
    55	        ExpiresAtUtc = expiresAtUtc;
    56	    }
    57	
    58	    /// <summary>
    59	    /// Gets the identifier of the user that owns this token.
    60	    /// </summary>
    61	    public Guid UserId { get; private set; }
    62	
    63	    /// <summary>
    64	    /// Gets the identifier shared by all tokens created from this session.
    65	    /// </summary>
    66	    public Guid FamilyId { get; private set; }
    67	
    68	    /// <summary>
    69	    /// Gets the one-way hash of the issued token.
    70	    /// </summary>
    71	    public string TokenHash { get; private set; }
    72	
    73	    /// <summary>
    74	    /// Gets the UTC instant at which this token expires.
    75	    /// </summary>
    76	    public DateTimeOffset ExpiresAtUtc { get; private set; }
    77	
    78	    /// <summary>
    79	    /// Gets the UTC instant at which this token was revoked, if applicable.
    80	    /// </summary>
    81	    public DateTimeOffset? RevokedAtUtc { get; private set; }
    82	
    83	    /// <summary>
    84	    /// Gets a value indicating whether this token is valid at the supplied UTC instant.
    85	    /// </summary>
    86	    /// <param name="utcNow">The current UTC instant.</param>
    87	    /// <returns><see langword="true"/> when the token is unrevoked and unexpired; otherwise, <see langword="false"/>.</returns>
    88	    public bool IsActive(DateTimeOffset utcNow) =>
    89	        RevokedAtUtc is null && ExpiresAtUtc > utcNow;
    90	
    91	    /// <summary>
    92	    /// Revokes this token at the supplied UTC instant.
    93	    /// </summary>
    94	    /// <param name="revokedAtUtc">The UTC instant at which the token was revoked.</param>
    95	    /// <exception cref="DomainException">Thrown when the supplied instant is not UTC.</exception>
    96	    public void Revoke(DateTimeOffset revokedAtUtc)
    97	    {
    98	        if (revokedAtUtc.Offset != TimeSpan.Zero)
    99	        {
   100	            throw new DomainException("Refresh token revocation time must be in UTC.");
   101	        }
   102	
   103	        RevokedAtUtc ??= revokedAtUtc;
   104	    }
   105	}
