    26	    }
    27	
    28	    /// <summary>Authenticates a user and starts a browser session.</summary>
    29	    [HttpPost("login")]
    30	    [ProducesResponseType<AuthenticationResponse>(StatusCodes.Status200OK)]
    31	    [ProducesResponseType(StatusCodes.Status401Unauthorized)]
    32	    public async Task<ActionResult<AuthenticationResponse>> Login(LoginUserCommand command, CancellationToken cancellationToken)
    33	    {
    34	        var session = await sender.Send(command, cancellationToken);
    35	        SetRefreshCookie(session.RefreshToken);
    36	        return Ok(session.Response);
    37	    }
    38	
    39	    /// <summary>Rotates the HttpOnly refresh cookie and returns a new access token.</summary>
    40	    [HttpPost("refresh")]
    41	    [ProducesResponseType<AuthenticationResponse>(StatusCodes.Status200OK)]
    42	    [ProducesResponseType(StatusCodes.Status401Unauthorized)]
    43	    public async Task<ActionResult<AuthenticationResponse>> Refresh(CancellationToken cancellationToken)
    44	    {
    45	        var refreshToken = Request.Cookies[_options.RefreshCookieName];
    46	        if (string.IsNullOrWhiteSpace(refreshToken)) { DeleteRefreshCookie(); return Unauthorized(); }
    47	        var session = await sender.Send(new RefreshSessionCommand(refreshToken), cancellationToken);
    48	        if (session is null) { DeleteRefreshCookie(); return Unauthorized(); }
    49	        SetRefreshCookie(session.RefreshToken);
    50	        return Ok(session.Response);
    51	    }
    52	
    53	    /// <summary>Revokes the refresh family held by the browser.</summary>
    54	    [HttpPost("logout")]
    55	    [ProducesResponseType(StatusCodes.Status204NoContent)]
    56	    public async Task<IActionResult> Logout(CancellationToken cancellationToken)
    57	    {
    58	        await sender.Send(new LogoutSessionCommand(Request.Cookies[_options.RefreshCookieName]), cancellationToken);
    59	        DeleteRefreshCookie();
    60	        return NoContent();
    61	    }
    62	
    63	    /// <summary>Gets the current user from a valid bearer token.</summary>
    64	    [Authorize]
    65	    [HttpGet("me")]
    66	    [ProducesResponseType<AuthenticatedUser>(StatusCodes.Status200OK)]
    67	    public async Task<ActionResult<AuthenticatedUser>> Me(CancellationToken cancellationToken)
    68	    {
    69	        var value = User.FindFirstValue(ClaimTypes.NameIdentifier);
    70	        if (!Guid.TryParse(value, out var userId)) return Unauthorized();
