   137	        return (new AuthenticationSession(new AuthenticationResponse(access.Token, access.ExpiresAtUtc, ToUser(user)), refreshValue), token);
   138	    }
   139	
   140	    private async Task RevokeFamilyAsync(Guid familyId, DateTimeOffset now, CancellationToken cancellationToken)
   141	    {
   142	        var activeTokens = await dbContext.RefreshTokens.Where(item => item.FamilyId == familyId && item.RevokedAtUtc == null && item.ExpiresAtUtc > now).ToListAsync(cancellationToken);
   143	        foreach (var token in activeTokens) token.Revoke(now);
   144	    }
   145	
   146	    private static AuthenticatedUser ToUser(ApplicationUser user) => new(user.Id, user.Email ?? string.Empty, user.DisplayName);
   147	}
