     1	import axios, { type AxiosError, type InternalAxiosRequestConfig } from "axios"
     2	import { environment } from "@/app/config/environment"
     3	import { useAuthStore } from "@/features/auth/auth-store"
     4	
     5	export const authClient = axios.create({
     6	  baseURL: environment.apiBaseUrl,
     7	  withCredentials: true,
     8	  headers: { "Content-Type": "application/json" },
     9	})
    10	export const apiClient = axios.create({
    11	  baseURL: environment.apiBaseUrl,
    12	  withCredentials: true,
    13	  headers: { "Content-Type": "application/json" },
    14	})
    15	
    16	let refreshPromise: Promise<string | null> | null = null
    17	let sessionEpoch = 0
    18	
    19	export const invalidateSession = () => {
    20	  sessionEpoch += 1
    21	  useAuthStore.getState().clearSession()
    22	}
    23	
    24	const refreshAccessToken = () => {
    25	  if (!refreshPromise) {
    26	    const refreshEpoch = sessionEpoch
    27	    refreshPromise = authClient
    28	      .post("/api/auth/refresh")
    29	      .then((response) => {
    30	        if (refreshEpoch !== sessionEpoch) return null
    31	
    32	        useAuthStore.getState().setSession(response.data)
    33	        return response.data.accessToken as string
    34	      })
    35	      .catch(() => {
    36	        if (refreshEpoch === sessionEpoch) invalidateSession()
    37	        return null
    38	      })
    39	      .finally(() => {
    40	        refreshPromise = null
    41	      })
    42	  }
    43	  return refreshPromise
    44	}
    45	
    46	apiClient.interceptors.request.use((config) => {
    47	  const token = useAuthStore.getState().accessToken
    48	  if (token) config.headers.Authorization = `Bearer ${token}`
    49	  return config
    50	})
    51	apiClient.interceptors.response.use(undefined, async (error: AxiosError) => {
    52	  const request = error.config as
    53	    (InternalAxiosRequestConfig & { _authRetried?: boolean }) | undefined
    54	  if (error.response?.status !== 401 || !request || request._authRetried)
    55	    return Promise.reject(error)
    56	  request._authRetried = true
    57	  const token = await refreshAccessToken()
    58	  if (!token) return Promise.reject(error)
    59	  request.headers.Authorization = `Bearer ${token}`
    60	  return apiClient(request)
    61	})
    62	
    63	export const restoreSession = async () => {
    64	  const restoreEpoch = sessionEpoch
    65	
    66	  try {
    67	    const session = await authClient
    68	      .post("/api/auth/refresh")
    69	      .then((response) => response.data)
    70	
    71	    if (restoreEpoch === sessionEpoch)
    72	      useAuthStore.getState().setSession(session)
    73	  } catch {
    74	    if (restoreEpoch === sessionEpoch) invalidateSession()
    75	  } finally {
    76	    useAuthStore.getState().finishRestoring()
    77	  }
    78	}
